import { Vex } from '@vex_dev/sdk';
import { Mastra } from 'mastra';

const vex = new Vex({ apiKey: process.env.VEX_API_KEY });
const mastra = new Mastra();

// Middleware for pricing workflow validation
mastra.workflow('pricing-engine')
  .step('calculatePrice', async (input) => {
    const priceData = await calculateDynamicPrice(input);

    // Vex validation before transition
    const result = await vex.validate({
      data: priceData,
      rules: ['pricing:accuracy'],
      context: { workflow: 'ecommerce-pricing' }
    });

    if (!result.valid) {
      throw new Error(`Pricing validation failed: ${result.issues}`);
    }

    return priceData;
  });

import { Vex } from '@vex_dev/sdk';
import { Mastra } from 'mastra';

const vex = new Vex({ apiKey: process.env.VEX_API_KEY });

mastra.agent('payment-agent')
  .tool('processPayment', async (paymentIntent) => {
    const response = await stripe.charges.create(paymentIntent);

    // Vex PCI validation
    const pciCheck = await vex.validate({
      data: response,
      rules: ['pci:dss'],
      context: { source: 'stripe-integration' }
    });

    if (pciCheck.issues?.length > 0) {
      console.warn('PCI violation detected:', pciCheck.issues);
      return { status: 'blocked', reason: 'PCI compliance failure' };
    }

    return { status: 'success', id: response.id };
  });

import { Vex } from '@vex_dev/sdk';
import { Mastra } from 'mastra';

const vex = new Vex({ apiKey: process.env.VEX_API_KEY });

mastra.agent('support-agent')
  .useMemory(async (query, context) => {
    const retrieved = await mastra.knowledge.retrieve(query);

    // Vex policy validation
    const policyCheck = await vex.validate({
      data: retrieved,
      rules: ['ftc:claims', 'policy:accuracy'],
      context: { type: 'refund-policy', timestamp: Date.now() }
    });

    return policyCheck.valid ? retrieved : null;
  })
  .handle('refundRequest', async (input) => {
    // Agent logic continues with validated context
    return `Current policy: ${input.policy}`;
  });
